package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Constructor;

class LineItemTest {

  @Test
  void testGetQuantity() throws Exception {
    // Arrange
    String name = "Test Item";
    int quantity = 5;
    long priceInMicros = 100000L;
    String currencyCode = "USD";

    // Use the LineItem class directly instead of reflection to avoid ClassNotFoundException
    Constructor<LineItem> constructor = LineItem.class.getDeclaredConstructor(String.class, int.class, long.class, String.class);
    constructor.setAccessible(true);
    LineItem lineItem = constructor.newInstance(name, quantity, priceInMicros, currencyCode);

    // Act
    int result = lineItem.getQuantity();

    // Assert
    assertEquals(quantity, result);
  }
}
